\begin{definition}[缺陷集]\label{def:pom-ind-defect-set}
在命题 \ref{prop:pom-ind-matrix-grammar} 的单块设定下，定义缺陷位置集合
\[
\mathcal D(J(x)):=\{t\in\{3,\dots,k\}:\ \sigma_t=3\}
=\{t\in\{3,\dots,k\}:\ i_t-i_{t-2}=2\}.
\]
\end{definition}

\begin{definition}[窗口值与外表值]\label{def:pom-window-value}
对 $\omega=\omega_1\cdots\omega_m\in\Omega_m$，定义窗口值
\[
N(\omega):=\sum_{k=1}^m \omega_k F_{k+1}.
\]
对 $x=x_1\cdots x_m\in X_m$，定义外表值
\[
V_m(x):=\sum_{k=1}^m x_k F_{k+1}.
\]
\leanverified{weight}
\leanverified{stableValue}
\end{definition}

\begin{definition}[扫描误差剖面]\label{def:spg-scan-error-profile}
在给定 $T$-不变概率测度 $\mu$ 下，对任意 $\mathsf P\in\mathcal{F}_\infty$ 定义
\[
\varepsilon_m(\mathsf P;\mu)
:=\inf\left\{\mu(g\neq \ind_{\mathsf P}): g\in L^\infty(\mathcal{F}_m),\ g(X)\subseteq\{0,1\}\right\}.
\]
\leanverified{scanError}
\end{definition}

\begin{definition}[折叠指标与投影熵率]\label{def:pom-fold-index}
令
\[
I_m:=\frac{|\Omega_m|}{|X_m|}=\frac{2^m}{F_{m+2}},
\qquad
S_Z(m):=\log I_m,
\qquad
h_Z:=\lim_{m\to\infty}\frac{S_Z(m)}{m}.
\]
$I_m$ 是折叠诱导的平均多重度指标，$S_Z(m)$ 与 $h_Z$ 分别刻画分辨率 $m$ 与单位分辨率的投影熵率。
\leanverified{foldIndex}
\leanpartial{foldIndex\_gt\_one}{仅覆盖 $m\geq 2$；$m=0,1$ 时 $I_m\leq 1$}
\leanverified{foldIndex\_strict\_mono\_of\_ge\_one}
\end{definition}

\begin{definition}[自然基准分布：均匀微态的折叠推前]\label{def:pom-wm-baseline}
令 $u_{\Omega_m}$ 表示 $\Omega_m=\{0,1\}^m$ 上的均匀分布（$u_{\Omega_m}(a)\equiv 2^{-m}$）。
定义 $X_m$ 上的自然基准分布
\[
w_m:=(\Fold_m)_*u_{\Omega_m},\qquad
w_m(x)=\frac{d_m(x)}{2^m}\quad(x\in X_m).
\]
它刻画了“均匀微态”在折叠后的输出分布（亦即把纤维多重度归一化为概率权重）。\footnote{为避免与第 \ref{sec:experiments} 节 Parry(PF) 基线的 $\pi_m$ 记号混淆，本文统一用 $w_m$ 表示该分布。旧稿中曾在碰撞矩/R\'enyi 指纹处使用 $\pi_m(x)=d_m(x)/2^m$ 的同义记号，但下文不再采用之。}
\end{definition}

\begin{lemma}[自由逆代换给出的纤维下界]\label{lem:pom-fiber-lower-bound-independent-sets}
对任意 $x\in X_m$，有
\[
d_m(x)\ \ge\ \#\mathsf{Ind}(G(x)).
\]
\end{lemma}

\begin{corollary}[熵增恒等式：最大熵提升的增量等于残差 KL]\label{cor:pom-ent-increase-equals-kl}
沿用上述记号，则有严格恒等式
\[
\boxed{\;
H(\mu^e)-H(\mu)=D_{\mathrm{KL}}(\mu\|\mu^e).
\;}
\]
\end{corollary}

\begin{corollary}[一个可计算的纤维下界]\label{cor:pom-fiber-lower-bound-dp}
对任意 $x\in X_m$，用引理 \ref{lem:pom-independence-dp-radius2} 的递推计算出 $a_k$，则
\[
d_m(x)\ge a_k.
\]
\end{corollary}

\begin{corollary}[熵单调化通道：\texorpdfstring{$Q_m\circ P_m$}{Q∘P} 的“窗口第二定律”]\label{cor:pom-second-law-Km}
对任意 $\mu\in\Delta(\Omega_m)$，有严格恒等式
\[
\boxed{\;
H(K_m\mu)-H(\mu)=D_{\mathrm{KL}}(\mu\|K_m\mu)\ \ge\ 0,
\;}
\]
并且等号当且仅当 $K_m\mu=\mu$（等价于 $\mu$ 在每条纤维上条件均匀）。
\end{corollary}

\begin{corollary}[I-投影的精确误差刻画：KL 距离即为“微观残差”]\label{cor:pom-Iproj-gap-exact}
沿用定理 \ref{thm:pom-kl-pythagoras-uniform} 的记号，固定任意 $\pi\in\Delta(X_m)$ 并取任意 $\mu\in\mathcal{C}_\pi$。
则
\[
\boxed{\;
D_{\mathrm{KL}}(\mu\|u_{\Omega_m})-D_{\mathrm{KL}}(\mu^e\|u_{\Omega_m})
=D_{\mathrm{KL}}(\mu\|\mu^e).
\;}
\]
\end{corollary}

\begin{proposition}[纤维自由度的二层分解]\label{prop:pom-fiber-decompose}
对任意 $x\in X_m$，记 $I(x)$ 为 $x$ 中可执行逆代换 $100\mapsto 011$ 的局部位点集合（以长度 $3$ 窗口计），并要求所选位点两两不相邻以避免重叠。则任意 $\omega\in\Fold_m^{-1}(x)$ 可视为"一个余量位 $b\in\{0,1\}$"与"一组不相邻逆代换位点"的组合；因此
\[
d_m(x)\le 2\cdot \#\{\text{路径图 }P_{|I(x)|}\text{ 的独立集}\}
\le 2F_{\lfloor m/2\rfloor+2}.
\]
\end{proposition}

\begin{proposition}[\texorpdfstring{$\kappa_m(\pi)$}{kappa} 的 KL 精确分解]\label{prop:pom-kappa-kl-decomposition}
对任意 $\pi\in\Delta(X_m)$，令 $w_m$ 为定义 \ref{def:pom-wm-baseline} 的自然基准分布。则有严格恒等式
\[
\boxed{\;
\kappa_m(\pi)=m\log 2\;-\;H(\pi)\;-\;D_{\mathrm{KL}}(\pi\|w_m)\; }.
\]
因此 $\kappa_m(\pi)\le m\log 2-H(\pi)$，且当且仅当 $\pi=w_m$ 时取等号。
\end{proposition}

\begin{corollary}[\texorpdfstring{$\bmod 3$}{mod 3} 相位阻碍：由分量长度决定]\label{cor:pom-fiber-signed-index-mod3}
\(\Gamma_x\) 的分量长度 \((\ell_i)\) 诱导一个可审计的阻碍类：是否出现 \(\ell_i\equiv 1\pmod 3\) 决定 \(\mathfrak{s}_m(x)\) 的消失与否。
当 \(\mathfrak{s}_m(x)\neq 0\) 时，其符号由 \(\ell_i\) 在上述 \(6\) 周期表中的落点完全决定，从而 \(\mathfrak{s}_m(x)\) 只依赖于候选位点图 \(\Gamma_x\) 的分量结构而不依赖外部解释层。
\end{corollary}

\begin{theorem}[纤维反射子：幂等 Markov 投影与固定点刻画]\label{thm:pom-fiber-reflector}
定义 Markov 算子
\[
K_m:=Q_m\circ P_m:\Delta(\Omega_m)\to\Delta(\Omega_m).
\]
则：
\begin{enumerate}
  \item $K_m$ 幂等：$K_m^2=K_m$；
  \item 对任意 $\mu$，若 $\pi=P_m\mu$，则 $K_m\mu=\mu^e$ 为 $\pi$ 的纤维均匀提升；
  \item 固定点满足：$K_m\mu=\mu$ 当且仅当 $\mu$ 在每条纤维上条件均匀（等价地 $\mu=\mu^e$）。
\end{enumerate}
\end{theorem}

\begin{corollary}[最大熵提升的 I-投影表述]\label{cor:pom-Iproj-maxent}
记 $u_{\Omega_m}$ 为 $\Omega_m$ 上的均匀分布。对任意固定 $\pi\in\Delta(X_m)$，约束集
\[
\mathcal{C}_\pi:=\{\nu\in\Delta(\Omega_m):P_m\nu=\pi\}
\]
为凸集，且其唯一最大熵元 $\mu^e=Q_m\pi$ 同时满足
\[
\boxed{\;
\mu^e=\arg\min_{\nu\in\mathcal{C}_\pi}D_{\mathrm{KL}}(\nu\|u_{\Omega_m})
\;=\;
\arg\max_{\nu\in\mathcal{C}_\pi}H(\nu).
\;}
\]
\end{corollary}

\begin{proposition}[跨分辨率相容的交换图]\label{prop:fold-omega-commute}
对任意 $m\ge 1$，下图交换：
\[
\begin{CD}
\Omega_{m+1} @>{\Fold_{m+1}}>> X_{m+1}\\
@V{\widetilde r_{m+1\to m}}VV @VV{\pi_{m+1\to m}}V\\
\Omega_m @>{\Fold_m}>> X_m.
\end{CD}
\]
即对任意 $\omega\in\Omega_{m+1}$ 有
\[
\Fold_m\bigl(\widetilde r_{m+1\to m}(\omega)\bigr)
\ =\
\pi_{m+1\to m}\bigl(\Fold_{m+1}(\omega)\bigr).
\]
\end{proposition}

\begin{corollary}[纤维下界的块级乘法级联]\label{cor:pom-fiber-lower-bound-cascade}
沿用定义 \ref{def:pom-carry-interference-graph}，并把 $J(x)=J_1\sqcup\cdots\sqcup J_r$ 按引理 \ref{lem:pom-ind-factorization} 分解为块。
记每块贡献
\[
I(J_\ell):=\#\mathsf{Ind}(G[J_\ell])\qquad(\ell=1,\dots,r).
\]
则对任意 $x\in X_m$ 都有
\[
\boxed{\;
d_m(x)\ \ge\ \prod_{\ell=1}^r I(J_\ell)\;}
\]
从而其对数纤维体积至少具有可加分解
\[
\boxed{\;
\log d_m(x)\ \ge\ \sum_{\ell=1}^r \log I(J_\ell).\;}
\]
\end{corollary}

\begin{corollary}[\texorpdfstring{$K_m$}{Km} 的谱与投影解释]\label{cor:pom-Km-spectrum}
把 $K_m$ 视为作用在 $\RR^{\Omega_m}$（或 $\CC^{\Omega_m}$）上的线性算子，则：
\begin{enumerate}
  \item $K_m$ 是（计数内积下的）正交投影，其像空间恰为纤维常值函数空间
  \[
  \mathrm{Im}(K_m)=\{f:\Omega_m\to\RR:\ f(a)=f(b)\ \text{当且仅当}\ \Fold_m(a)=\Fold_m(b)\}.
  \]
  \item $\mathrm{rank}(K_m)=|X_m|$，并且其谱仅由 $\{0,1\}$ 构成：特征值 $1$ 的重数为 $|X_m|$，特征值 $0$ 的重数为 $|\Omega_m|-|X_m|=2^m-|X_m|$。
\end{enumerate}
\end{corollary}

\begin{lemma}[纤维 KL 分解：残差为纤维内非均匀的平均]\label{lem:pom-fiberwise-kl}
取任意 $\mu\in\Delta(\Omega_m)$，令 $\pi=P_m\mu$。对每个 $x\in X_m$ 定义纤维条件分布
\[
\mu_x(a):=
\begin{cases}
\mu(a)/\pi(x),& a\in \Fold_m^{-1}(x),\ \pi(x)>0,\\
0,& a\in \Fold_m^{-1}(x),\ \pi(x)=0,
\end{cases}
\]
并令 $u_x$ 为该纤维上的均匀分布 $u_x(a)=1/d_m(x)$（$a\in\Fold_m^{-1}(x)$）。
则对纤维均匀提升 $\mu^e=Q_m\pi$，有链式恒等式
\[
\boxed{\;
D_{\mathrm{KL}}(\mu\|\mu^e)=\sum_{x\in X_m}\pi(x)\,D_{\mathrm{KL}}(\mu_x\|u_x).
\;}
\]
\end{lemma}

\begin{lemma}[单块情形的局部递推：\texorpdfstring{$a_t=a_{t-1}+a_{t-2}$}{a=a+a} 与 \texorpdfstring{$a_t=a_{t-1}+a_{t-3}$}{a=a+a} 的分岔]\label{lem:pom-ind-local-recurrence}
沿用引理 \ref{lem:pom-independence-dp-radius2} 的记号。
设 $J(x)$ 自身为单块（即对所有 $t$ 有 $i_{t+1}-i_t\le 2$）。则对 $t\ge 3$：
\begin{enumerate}
  \item 若 $i_t-i_{t-2}>2$，则 $p(t)=t-2$，从而
  \[
  a_t=a_{t-1}+a_{t-2};
  \]
  \item 若 $i_t-i_{t-2}=2$（等价于 $i_{t-1}=i_t-1$ 且 $i_{t-2}=i_t-2$），则 $p(t)=t-3$，从而
  \[
  a_t=a_{t-1}+a_{t-3}.
  \]
\end{enumerate}
\end{lemma}

\begin{corollary}[旋度控制下的势函数重构与最优常数]\label{cor:spg-cube-potential-reconstruction-by-curl}
设 \(v\in C^1(I^n;\RR^n)\)，并令对应 \(1\)-形式
\(
\omega:=\sum_{i=1}^n v_i\,\dd x_i
\)。
则存在 \(U\in C^2(I^n)\) 使得
\begin{equation}\label{eq:spg-cube-vectorfield-gradient-approx}
\|v-\nabla U\|_\infty\le \frac14\,\|\dd\omega\|_\infty,
\end{equation}
其中 \(\dd\omega\) 为 \(2\)-形式（外微分意义下的旋度张量）。
并且常数 \(\frac14\) 为最优：对任意 \(C<\frac14\)，存在某个 \(v\) 使得对所有 \(U\in C^1(I^n)\) 均有 \(\|v-\nabla U\|_\infty> C\,\|\dd\omega\|_\infty\)。
\end{corollary}

\begin{corollary}[最大纤维达到者的指数稀薄率（两种自然测度）]\label{cor:pom-maxfiber-rare-uniform}
令 \(\mathcal{M}_m:=\{x\in X_m:\ d_m(x)=D_m\}\)。在类型均匀测度 \(U_m=\mathrm{Unif}(X_m)\) 与微态均匀推前测度 \(w_m(x)=d_m(x)/2^m\) 下，有
\[
U_m(\mathcal{M}_m)=\Theta(\varphi^{-m}),
\qquad
w_m(\mathcal{M}_m)=\Theta\!\left(\left(\frac{\sqrt{\varphi}}{2}\right)^m\right),\qquad \frac{\overline d_m}{D_m}
=\Theta\!\left(\left(\frac{2}{\varphi^{3/2}}\right)^m\right).
\]
其中前两项分别对应“类型均匀”与“微态均匀推前”两种自然采样口径下的极值命中率；更精确的闭式公式见推论 \ref{cor:pom-maxfiber-rarity-two-measures}。
\end{corollary}

\begin{corollary}[碰撞条件下的隐藏位跃迁概率闭式与代数极限]\label{cor:pom-hiddenbit-jump-probability-closed-form}
在碰撞关系 \(R_m\) 上取均匀分布（即从所有碰撞有序对 \((\omega,\omega')\in R_m\) 等概率抽取）。
则
\[
\boxed{\;
\mathbb{P}\bigl[b(\omega)\neq b(\omega')\ \big|\ (\omega,\omega')\in R_m\bigr]
=\frac{2|J_m|}{|R_m|}
=\frac{2S_2(m-2)}{S_2(m)}\;}
\]
并且令 \(r_2:=\rho(A_2)\) 为命题 \ref{prop:pom-s2-recurrence} 的三态碰撞核 \(A_2\) 的 Perron 根（等价地，为 \(\lambda^3-2\lambda^2-2\lambda+2=0\) 的最大实根），则极限存在且
\[
\lim_{m\to\infty}\mathbb{P}\bigl[b(\omega)\neq b(\omega')\ \big|\ (\omega,\omega')\in R_m\bigr]
=\frac{2}{r_2^2}.
\]
\end{corollary}

\begin{corollary}[超平面计数的可逆性：由 \texorpdfstring{$|V|$}{|V|} 与 \texorpdfstring{$\{|\Theta|\}$}{|Theta|} 重建分量长度谱]\label{cor:pom-fiber-hyperplane-spectrum-invertibility}
设 \(\mathcal F_x\cong\prod_{i=1}^r\Gamma_{\ell_i}\)，并记顶点数 \(V_x:=|V(\mathcal F_x)|\)，以及 \(\mathcal M_x:=\{|\Theta|\}\) 为 \(\mathcal F_x\) 全部 \(\Theta\)-类边数的多重集。
则 \((V_x,\mathcal M_x)\) 唯一确定长度谱多重集
\(
\mathsf{Spec}_{\square}(x)=\{\ell_1,\dots,\ell_r\}
\)；
从而在该纤维类上，超平面统计 \(\mathcal M_x\)（配合基数 \(V_x\)）在不依赖实现细节的意义下确定 \(\mathcal F_x\) 的 Cartesian 素因子分解与图同构类（推论 \ref{cor:pom-fiber-reconstruction-spectrum-complete}）。
\end{corollary}

\begin{corollary}[椭圆门的乘法几何外置：超平面翻转 \texorpdfstring{$\leftrightarrow$}{<->} 素数尺度更新]\label{cor:pom-theta-godelization-ellipse-multiplicative-embedding}
沿用定理 \ref{thm:pom-theta-godelization-prime-valuation-isometry} 的设定，并取椭圆门族 \(\{E_r\}_{r>0}\) 的乘法律 \(E_r\odot E_s=E_{rs}\)（定理 \ref{thm:group-jg-ellipse-prime-homomorphism}）。
若进一步取 \(\lambda\) 使得 \(g_\lambda(v)\in\QQ_{>0}\)（例如令 \(\lambda(H)\) 为互异素数），则映射
\[
\mathcal E_\lambda:V(\mathcal F_x)\to\{E_r\}_{r>0},\qquad v\longmapsto E_{g_\lambda(v)}
\]
为单射。
并且在 \(\mathcal F_x\) 上跨越一条超平面 \(H\) 的基本边操作，对应于 \(g_\lambda\) 在素数 \(\lambda(H)\) 上的乘/除更新，从而把纤维内部的立方体几何嵌入到椭圆参数的乘法几何之中。
\end{corollary}

\begin{theorem}[整数尺度的线性标量化阈值]\label{thm:metallic-integer-scalarization-threshold}
沿用命题 \ref{prop:metallic-linear-scalarization-threshold} 的标量化目标
\[
J_\beta(A):=h_Z(A)-\beta\,\kappa(A),
\qquad
\kappa(A)=\frac{A}{\log\lambda_A}.
\]
在整数约束 \(A\in\ZZ_{\ge 1}\) 下，帕累托集合缩减为 \(\{1,2\}\)。
因此存在唯一阈值
\[
\beta_{\ZZ}
:=
\frac{h_Z(2)-h_Z(1)}{\kappa(2)-\kappa(1)}
=
\frac{\log\!\left(\dfrac{3\varphi}{2(1+\sqrt2)}\right)}
{\dfrac{2}{\log(1+\sqrt2)}-\dfrac{1}{\log\varphi}}
\approx 0.0277519138993265,
\]
其中 \(\varphi=(1+\sqrt5)/2\)。
并且最优整数尺度满足严格相变律
\[
A_\beta^{\ZZ}
=
\begin{cases}
2,& 0\le \beta<\beta_{\ZZ},\\[2mm]
\{1,2\},& \beta=\beta_{\ZZ},\\[2mm]
1,& \beta>\beta_{\ZZ}.
\end{cases}
\]
\end{theorem}

\begin{proposition}[超平面统计与局部 Markov 性的张量化]\label{prop:pom-fiber-hyperplane-tensorization}
设 \(\mathcal F_x\cong\prod_{i=1}^r\Gamma_{\ell_i}\)。
则：
\begin{enumerate}
  \item \textbf{（超平面计数张量化）}
  对任意因子 \(j\) 与其内部坐标 \(a\in\{1,\dots,\ell_j\}\)，
  令 \(\Theta_{j,a}\) 为在第 \(j\) 个因子上沿第 \(a\) 坐标翻转的 \(\Theta\)-类，则
  \[
  |\Theta_{j,a}|
  =\bigl(F_aF_{\ell_j-a+1}\bigr)\cdot\prod_{i\neq j}F_{\ell_i+2}.
  \]
  \item \textbf{（体相概率张量化）}
  在 \(\prod_i V(\Gamma_{\ell_i})\) 上的均匀测度严格分解为各因子的均匀测度之张量积；
  当 \(\ell_i\to\infty\) 且窗口位置保持体相（两端距离同时趋于无穷）时，
  各因子的局部统计由命题 \ref{prop:pom-unif-xn-local-limit-parry} 收敛到 Parry 测度，
  因而乘积纤维在局部上收敛到独立张量积测度。
  \item \textbf{（可加观测量的 CLT）}
  对分量可加的观测量（例如“开关坐标为 \(1\)”的计数），其均值与方差密度按分量相加，并在体相极限中满足 CLT。
\end{enumerate}
\end{proposition}

\begin{theorem}[超立方体上的最优有界 Poincar\'e--Stokes 逆算子]\label{thm:spg-cube-optimal-bounded-poincare-stokes-inverse}
在定义 \eqref{eq:spg-cube-homotopy-operator-Kk} 的设定下：
\begin{enumerate}
  \item 对任意 \(\omega\in\Omega^k_{\mathrm{sm}}(I^n)\)（\(k\ge 1\)）成立严格同伦恒等式
  \begin{equation}\label{eq:spg-cube-homotopy-identity}
  \dd(K_k\omega)+K_{k+1}(\dd\omega)=\omega.
  \end{equation}
  特别地，若 \(\dd\omega=0\)，则 \(\omega=\dd(K_k\omega)\)。
  \item 存在与 \(n\) 无关的最优常数界
  \begin{equation}\label{eq:spg-cube-Kk-supnorm-bound}
  \|K_k\omega\|_\infty\le \frac{1}{2k}\,\|\omega\|_\infty.
  \end{equation}
  并且常数 \(\frac{1}{2k}\) 在如下意义下最优：若 \(R:Z^k_{\mathrm{sm}}(I^n)\to\Omega^{k-1}_{\mathrm{sm}}(I^n)\) 为线性算子（\(Z^k_{\mathrm{sm}}(I^n):=\{\omega\in\Omega^k_{\mathrm{sm}}(I^n):\dd\omega=0\}\)），满足对所有闭 \(k\)-形式 \(\omega\) 有 \(\dd(R\omega)=\omega\)，则其算子范数满足
  \begin{equation}\label{eq:spg-cube-optimal-lower-bound}
  \|R\|_{\infty\to\infty}\ge \frac{1}{2k}.
  \end{equation}
\end{enumerate}
\end{theorem}

\begin{corollary}[二轴复杂度分离律：熵率不降，但降分辨率的最小重写支持为线性尺度]\label{cor:pom-two-axis-separation}
在序列级，折叠因子像 \(Y_m\) 的信息率不损失：对任意 \(m\ge 2\)，\(h_{\mathrm{top}}(Y_m)=\log 2\)（定理 \ref{thm:pom-entropy-saturation}），并且对任意输出轨道 \(y\in Y_m\) 有有限对一缺陷上界 \( |\Phi_m^{-1}(y)|\le 2^{m-1}\)（注 \ref{rem:pom-finite-defect}）。
\par
但在跨分辨率降阶时，把朴素微态截断 \(r_{m+1\to m}\) 修正为折叠一致的 coarse-graining \(\widetilde r_{m+1\to m}\)（小节 \ref{subsec:fold-gauge-anomaly}）所需改动支持规模由规范差 \(G_m(\omega)\) 给出（定义 \ref{def:fold-gauge-anomaly}），并满足：
\begin{enumerate}
  \item \textbf{最坏情形：}对任意 \(m\ge 1\)，存在输入 \(\omega^\star(m)\in\Omega_{m+1}\) 使 \(G_m(\omega^\star)=m\)（定理 \ref{thm:fold-gauge-anomaly-max}），即纠偏可触及 \(\Theta(m)\) 位；
  \item \textbf{均匀基线：}在审计窗口 \(m\le 20\) 的精确枚举中（表 \ref{tab:fold_gauge_anomaly_stats}），\(\bar G_m/m\) 已上升到约 \(0.4176\)；并且该线性尺度可被封口为闭式常数密度定律：
  \[
  \lim_{m\to\infty}\frac{\bar G_m}{m}=\frac{4}{9}
  \]
  （定理 \ref{thm:fold-gauge-anomaly-density}）。因此在均匀微态基线下，降一阶分辨率的“典型重写支持规模”满足 \(\bar G_m\sim (4/9)m\)。
\end{enumerate}
因此在本文体系内，“每步信息率（熵率）”与“降一阶分辨率所需的最小重写支持规模”构成两条正交轴：折叠的多对一并不意味着熵率压缩；它把代价迁移为跨尺度一致性所需的全局支持重写量。
\end{corollary}

\begin{theorem}[\(\Theta\)-坐标化的等距性与素数赋值等距字典]\label{thm:pom-theta-godelization-prime-valuation-isometry}
取任意稳定类型 \(x\in X_m\)，并在同构 \(V(\mathcal F_x)\cong \mathsf{Ind}(\Gamma_x)\) 下把纤维重构图 \(\mathcal F_x\) 视为 partial cube（推论 \ref{cor:pom-fiber-reconstruction-median-partialcube-cat0}）。
取基点 \(v_0\in V(\mathcal F_x)\)，并令 \(\iota:=\iota_{v_0}\) 为定义 \ref{def:pom-theta-halfspace-coordinates} 的半空间坐标化。
则对任意 \(u,v\in V(\mathcal F_x)\) 有严格恒等式
\[
\boxed{\;
d_{\mathcal F_x}(u,v)=\sum_{H\in\mathrm{Hyp}(\mathcal F_x)}
\bigl|\iota(u)_H-\iota(v)_H\bigr|. \;}
\]
进一步，取任意单射标号 \(\lambda:\mathrm{Hyp}(\mathcal F_x)\hookrightarrow\mathbb P\)（\(\mathbb P\) 为素数集），并定义 \(\Theta\)--Gödel 标度
\[
g_\lambda:V(\mathcal F_x)\to\QQ_{>0},\qquad
g_\lambda(v):=\prod_{H\in\mathrm{Hyp}(\mathcal F_x)}\lambda(H)^{\iota(v)_H}.
\]
则：
\begin{enumerate}
  \item \(g_\lambda\) 为单射，且对每个 \(H\in\mathrm{Hyp}(\mathcal F_x)\) 有
  \[
  v_{\lambda(H)}\bigl(g_\lambda(v)\bigr)=\iota(v)_H\in\{0,1\};
  \]
  \item 若定义素数赋值的 \(\ell^1\) 距离
  \[
  d_\lambda(u,v):=\sum_{H\in\mathrm{Hyp}(\mathcal F_x)}
  \left|v_{\lambda(H)}(g_\lambda(u))-v_{\lambda(H)}(g_\lambda(v))\right|,
  \]
  则对一切 \(u,v\in V(\mathcal F_x)\) 有 \(d_\lambda(u,v)=d_{\mathcal F_x}(u,v)\)。
\end{enumerate}
因此 \(\mathcal F_x\) 的图距离可等距地算术化为素数赋值向量的 \(\ell^1\) 距离。
\end{theorem}

